    protected function prepareLineToImport(\StdClass $oLine)
    {
        $oReturn = new \StdClass;
        $message = null;
        $status = true;
        $em = $this->getEntityManager();

        if (property_exists($oLine, 'campanhaId')) {
            $campanha = $em->getRepository('\App\Entity\Campanha')
                ->createQueryBuilder('t')
                ->select('t.id')
                ->where('t.id = :campanhaId')
                ->setParameter('campanhaId', $oLine->campanhaId)
                ->getQuery()->getScalarResult();
        }

        if (!empty($campanha)) {
            $a = (array) $oLine;
            $oReturn->campanha_id = $this->getValueToEntity('campanhaId', $a);
            // $oReturn->participante_id = $participante[0]['id'];
            $oReturn->codigoExterno = $this->getValueToEntity('codigoExterno', $a);
            $oReturn->cpf = $this->getValueToEntity('cpf', $a);
            $oReturn->dtNascimento = $this->getValueToEntity('dtNascimento', $a);
            $oReturn->nome = $this->getValueToEntity('nome', $a);
            $oReturn->sexo = $this->getValueToEntity('sexo', $a);
            $oReturn->rua = $this->getValueToEntity('rua', $a);
            $oReturn->numero = $this->getValueToEntity('numero', $a);
            $oReturn->complemento = $this->getValueToEntity('complemento', $a);
            $oReturn->bairro = $this->getValueToEntity('bairro', $a);
            $oReturn->cidade = $this->getValueToEntity('cidade', $a);
            $oReturn->codigoLocal = $this->getValueToEntity('codigoLocal', $a);
            $oReturn->estado = $this->getValueToEntity('estado', $a);
            $oReturn->pais = $this->getValueToEntity('pais', $a);
            $oReturn->cep = $this->getValueToEntity('cep', $a);
            $oReturn->telefone = $this->getValueToEntity('telefone', $a);
            $oReturn->celular = $this->getValueToEntity('celular', $a);
            $oReturn->email = $this->getValueToEntity('email', $a);
            $oReturn->descricao = $this->getValueToEntity('descricao', $a);
        } else {
            $message = 'Campanha não encontrada';
            $status = false;
        }

        return [
            'object' => (array) $oLine, # Objeto a ser importado
            'status' => $status, # true -> Sucesso, false -> Falha
            'message' => $message, # Mensagem de erro
        ];
    }

    public function fetchCollection($params = [], $filters = [], $orders = [], $page = 1, $limit = 100)
    {
        $result = parent::fetchCollection($params, $filters, $orders, $page, $limit);
