            // Não trata
        } else {
            foreach ($result as $k => $data) {
                $result[$k]['cpf'] = Cryptor::cryptoJsAesEncrypt('123456', $result[$k]['cpf']);
                $result[$k]['nome'] = Cryptor::cryptoJsAesEncrypt('123456', $result[$k]['nome']);
            }
        }

        return $result;
    }

