    /**
     * Valida os campos que podem ser filtrados no select
     * @param  \Doctrine\ORM\QueryBuilder $collection
     * @param  Array $filters
     * @return \Doctrine\ORM\QueryBuilder
     */
    protected function getFilters($collection, $filters)
    {
        $where = '1=1';

        if (!empty($filters['somenteExcluidos']) && $filters['somenteExcluidos'] === 'yes') {
            $where .= ' AND t.deletedAt IS NOT NULL AND t.status = 0';
        } else {
            $where .= ' AND t.deletedAt IS NULL AND t.status = 1';
        }

        if (!empty($filters['id'])) {
            $where .= ' AND t.id = :id';
            $collection->setParameter('id', $filters['id']);
        }

        if (!empty($filters['campanhaId'])) {
            $where .= ' AND t.campanhaId = :campanhaId';
            $collection->setParameter('campanhaId', $filters['campanhaId']);
        }

        if (!empty($filters['empresaId'])) {
            $where .= ' AND t.empresaId = :empresaId';
            $collection->setParameter('empresaId', $filters['empresaId']);
        }

        if (!empty($filters['participantePrincipalId'])) {
            $where .= ' AND t.participantePrincipalId = :participantePrincipalId';
            $collection->setParameter('participantePrincipalId', $filters['participantePrincipalId']);
        }

        if (!empty($filters['token'])) {
            $where .= ' AND tp.token = :token';
            $collection->setParameter('token', $filters['token']);
        }

        if (!empty($filters['cpf'])) {
            $where .= ' AND t.cpf = :cpf';
            $cpf = preg_replace('/^0+/', '', $filters['cpf']);
            $collection->setParameter('cpf', $cpf);
        }

        if (!empty($filters['nome'])) {
            $where .= ' AND lower(t.nome) LIKE lower(:nome)';
            $collection->setParameter('nome', '%' . $filters['nome'] . '%');
        }

        if (!empty($filters['codigoLocal'])) {
            $where .= ' AND lower(t.codigoLocal) LIKE lower(:codigoLocal)';
            $collection->setParameter('codigoLocal', '%' . $filters['codigoLocal'] . '%');
        }

        if (!empty($filters['departamento'])) {
            $where .= ' AND lower(t.departamento) LIKE lower(:departamento)';
            $collection->setParameter('departamento', '%' . $filters['departamento'] . '%');
        }

        if (!empty($filters['matricula'])) {
            $where .= ' AND lower(t.matricula) LIKE lower(:matricula)';
            $collection->setParameter('matricula', '%' . $filters['matricula'] . '%');
        }

        if (!empty($filters['tipo'])) {
            if ($filters['tipo'] === 'principal') {
                $where .= ' AND t.participantePrincipalId IS NULL';
            } else {
                $where .= ' AND t.participantePrincipalId IS NOT NULL';
            }
        }

        if (!empty($filters['dtNascimento'])) {
            $where .= ' AND t.dtNascimento = :dtNascimento';
            $collection->setParameter('dtNascimento', $filters['dtNascimento']);
        }

        if (!empty($filters['comAdesao'])) {
            if ($filters['comAdesao'] === 'yes') {
                $where .= ' AND t.dtAceite IS NOT NULL';
            } else {
                $where .= ' AND t.dtAceite IS NULL';
            }
        }

        if (!empty($filters['createdAt'])) {
            switch ($filters['createdAt']) {
                case 'today':
                    $where .= ' AND t.createdAt BETWEEN \'' . date('Y-m-d') . ' 00:00\'';
                    $where .= ' AND \'' . date('Y-m-d') . ' 23:59:59\'';
            }
        }

        if (!empty($filters['codigoExterno'])) {
            // $where .= ' AND lower(t.codigoExterno) LIKE lower(:codigoExterno)';
            // $collection->setParameter('codigoExterno', '%' . $filters['codigoExterno'] . '%');
            // $where .= ' AND t.codigoExterno = :codigoExterno';
            $collection->leftJoin('\App\Entity\CampanhaParticipante', 'cpt', 'WITH', 'cpt.id = t.participantePrincipalId');
            $where .= ' AND  (t.codigoExterno = :codigoExterno OR cpt.codigoExterno = :codigoExterno)';
            $collection->setParameter('codigoExterno', $filters['codigoExterno']);
        }

        if (!empty($filters['codigoExternoExato'])) {
            // $where .= ' AND t.deletedAt < NOW()';
            // $where .= ' AND cast(t.codigoExterno AS CHAR(20)) like \'%:codigoExternoExato%\'';
            // $where .= ' AND CONCAT(t.codigoExterno) = :codigoExternoExato';
            // $where .= ' AND CONCAT(t.codigoExterno) like \'%:codigoExternoExato%\'';
            // $where .= ' AND CONVERT(t.codigoExterno,char) like \'%:codigoExternoExato%\'';
            $where .= ' AND t.codigoExterno = :codigoExternoExato';
            $collection->setParameter('codigoExternoExato', $filters['codigoExternoExato']);
        }

        if (!empty($filters['nomeCodigo'])) {
            $where .= ' AND (lower(t.nome) LIKE lower(:participante)';
            $where .= ' OR  t.codigoExterno = :participante_codigo)';
            $collection->setParameter('participante', '%' . $filters['nomeCodigo'] . '%');
            $collection->setParameter('participante_codigo', $filters['nomeCodigo']);
        }

        if (!empty($filters['nomeCodigoCpf'])) {
            $where .= ' AND (lower(t.nome) LIKE lower(:participante)';
            $where .= ' OR t.cpf = :participante_cpf';
            $where .= ' OR  t.codigoExterno = :participante_codigo)';
            $collection->setParameter('participante', '%' . $filters['nomeCodigoCpf'] . '%');
            $collection->setParameter('participante_codigo', $filters['nomeCodigoCpf']);
            $collection->setParameter('participante_cpf', $filters['nomeCodigoCpf']);
        }


        if (!empty($filters['codigoExternoLike'])) {
            $collection->leftJoin('\App\Entity\CampanhaParticipante', 'cpt', 'WITH', 'cpt.id = t.participantePrincipalId');
            $where .= ' AND  (t.codigoExterno LIKE :codigoExternoLike OR cpt.codigoExterno LIKE :codigoExternoLike)';
            $collection->setParameter('codigoExternoLike', '%' . $filters['codigoExternoLike'] . '%');
        }

        if (!empty($filters['matricula'])) {
            $where .= ' AND lower(t.matricula) LIKE lower(:matricula)';
            $collection->setParameter('matricula', '%' . $filters['matricula'] . '%');
        }

        $collection->where($where);
        //         $this->debbug_query_collection = true;
        return $collection;
    }

    /**
     * Query utilizada para as consultas
     * @param  Array $params
     * @return  \Doctrine\ORM\QueryBuilder
     */
    protected function getQueryToFeatchCollection()
    {
        $fieldAdapter = $this->getFieldAdapter();
        $collection = $this->createQueryBuilder("t")
            ->select($fieldAdapter->getSqlFields())
            ->leftJoin('\App\Entity\Campanha', 'cp', 'WITH', 'cp.id = t.campanhaId')
            ->leftJoin('\App\Entity\TokenParticipante', 'tp', 'WITH', 'tp.participanteId = t.id')
            ->leftJoin('\App\Entity\Empresa', 'e', 'WITH', 'e.id = t.empresaId')
            ->leftJoin('\App\Entity\CampanhaParticipantePagador', 'p', 'WITH', 'p.id = t.pagadorId');

        return $collection;
    }

    protected function setItemsToEntity($aValues, $entity = null, $oldEntity = null)
    {
        $entity = $this->getEntity();
        $em = $this->getEntityManager();

        $entity->setCodigoExterno($this->getValueToEntity('codigoExterno', $aValues, $oldEntity));
        $entity->setCampanhaId($this->getValueToEntity('campanhaId', $aValues, $oldEntity));
        $entity->setPagadorId($this->getValueToEntity('pagadorId', $aValues, $oldEntity));
        $entity->setDtAceite($this->getValueToEntity('dtAceite', $aValues, $oldEntity));
        $entity->setCodigoLocal($this->getValueToEntity('codigoLocal', $aValues, $oldEntity));
        if (is_null($oldEntity)) {
            $entity->setCreatedAt(new \DateTime());
            $entity->setUpdatedAt(new \DateTime());
            $entity->setUuid(Uuid::uuid4());
            $entity->setCol5($entity->getCodigoExterno());
        } else {
            $entity->setCreatedAt(!empty($entity->getCreatedAt()) ? $entity->getCreatedAt() : new \DateTime());
            $entity->setUpdatedAt(new \DateTime());
        }

        $entity->setDtAceiteLgpd($this->getValueToEntity('dtAceiteLgpd', $aValues, $oldEntity));
        if (empty($entity->getDtAceite())) {
            $oCampanha = $this->_em->getRepository('\App\Entity\Campanha')->findOneBy(['id' => $entity->getCampanhaId()]);
            if ($oCampanha && $oCampanha->getTipo() === 2) {
                $entity->setDtAceite(new \DateTime());
            } else {
                $entity->setDtAceite(null);
            }
        } else {
            $entity->setDtAceite(new \DateTime($entity->getDtAceite()));
        }
        $entity->setDeletedAt($this->getValueToEntity('deletedAt', $aValues, $oldEntity));
        if (empty($entity->getDeletedAt())) {
            $entity->setDeletedAt(null);
        } else {
            $entity->setDeletedAt(new \DateTime($entity->getDeletedAt()));
        }

        if (empty($entity->getDtAceiteLgpd())) {
            $entity->setDtAceiteLgpd(null);
        } elseif (!empty($entity->getDtAceiteLgpd())) {
            $entity->setDtAceiteLgpd(new \DateTime($entity->getDtAceiteLgpd()));
        }

        $entity->setEmpresaId($this->getValueToEntity('empresaId', $aValues, $oldEntity));
        $entity->setCampanhaId($this->getValueToEntity('campanhaId', $aValues, $oldEntity));
        if ($participanteId = $this->getValueToEntity('participantePrincipalId', $aValues, $oldEntity)) {
            $entity->setParticipantePrincipalId($participanteId);
        }

        $entity->setStatus($this->getValueToEntity('status', $aValues, $oldEntity));
        if (!$oldEntity && empty($entity->getStatus())) {
            $entity->setStatus(1);
        }

        if ($this->getValueToEntity('participantePrincipalCodigo', $aValues, null)) {
            $participantePrincipal = $this->getParticipantePrincipalFromCodigo($entity->getCampanhaId(), $aValues['participantePrincipalCodigo']);
            if (empty($participantePrincipal)) {
                throw new \Exception('Participante Principal nao encontrado', 404);
            } else {
                $entity->setParticipantePrincipalId($participantePrincipal['t_id']);
            }
        }

        if (!empty($entity->getParticipantePrincipalId())) {
            if (empty($participantePrincipal)) {
                $participantePrincipal = $this->getParticipantePrincipalFromCodigo($entity->getCampanhaId(), null, $entity->getParticipantePrincipalId());
            }

            if (empty($participantePrincipal)) {
                throw new \Exception('Codigo Externo nao encontrado', 404);
            }

            $codigoExterno = $this->getNextCodigoDependente($entity->getParticipantePrincipalId());
            $entity->setCodigoExterno($codigoExterno);
        }

        $entity->setCpf($this->getValueToEntity('cpf', $aValues, $oldEntity));
        $entity->setNome($this->getValueToEntity('nome', $aValues, $oldEntity));
        $entity->setMatricula($this->getValueToEntity('matricula', $aValues, $oldEntity));

        $entity->setSexo($this->getValueToEntity('sexo', $aValues, $oldEntity));
        if (empty($entity->getSexo())) {
            $entity->setSexo(0);
        }

        $entity->setDtNascimento($this->getValueToEntity('dtNascimento', $aValues, $oldEntity));
        if ($entity->getDtNascimento() === '') {
            $entity->setDtNascimento(null);
        } elseif (!empty($entity->getDtNascimento())) {
            if (strpos($entity->getDtNascimento(), '/')) {
                $entity->setDtNascimento(implode('-', array_reverse(explode('/', $entity->getDtNascimento()))));
            } elseif (is_numeric($entity->getDtNascimento())) {
                $unix_date = ($entity->getDtNascimento() - 25569) * 86400;
                $entity->setDtNascimento(gmdate("d-m-Y", $unix_date));
            }
            $entity->setDtNascimento(new \DateTime($entity->getDtNascimento()));
        }

        $entity->setTelefone($this->getValueToEntity('telefone', $aValues, $oldEntity));
        $entity->setCelular($this->getValueToEntity('celular', $aValues, $oldEntity));
        $entity->setEmail($this->getValueToEntity('email', $aValues, $oldEntity));
        $entity->setDescricao($this->getValueToEntity('descricao', $aValues, $oldEntity));

        $entity->setRua($this->getValueToEntity('rua', $aValues, $oldEntity));
        $entity->setNumero($this->getValueToEntity('numero', $aValues, $oldEntity));
        $entity->setComplemento($this->getValueToEntity('complemento', $aValues, $oldEntity));
        $entity->setBairro($this->getValueToEntity('bairro', $aValues, $oldEntity));
        $entity->setCidade($this->getValueToEntity('cidade', $aValues, $oldEntity));
        $entity->setEstado($this->getValueToEntity('estado', $aValues, $oldEntity));
        $entity->setCep($this->getValueToEntity('cep', $aValues, $oldEntity));
        $entity->setDepartamento($this->getValueToEntity('departamento', $aValues, $oldEntity));
        $entity->setCargo($this->getValueToEntity('cargo', $aValues, $oldEntity));
        // dd($entity);exit;
        return $entity;
    }

    protected function getNextCodigoDependente($participante_id)
    {
        $sql = "
            select concat(
                    codigo_externo,
                    FLOOR(RAND()*(99-1+1)+1)
                ) as codigo_externo
            from campanha_participante where id={$participante_id};
        ";

        $em = $this->getEntityManager();
        $stmt = $em->getConnection()->prepare($sql);
        $stmt->execute();
        $result = $stmt->fetchAll();

        return empty($result) ? null : $result[0]['codigo_externo'];
    }
