    private function getParticipantePrincipalFromCodigo($campanhaId, $participanteCodigoExterno = null, $participanteId = null)
    {
        $em = $this->getEntityManager();
        $collection = $this->createQueryBuilder("t");
        $where = "t.campanhaId = :campanhaId";
        $where .= " AND t.deletedAt IS NULL";

        if (!is_null($participanteCodigoExterno)) {
            $where .= " AND t.codigoExterno = :codigoExterno";
            $collection->setParameter("codigoExterno", $participanteCodigoExterno);
        } elseif (!is_null($participanteId)) {
            $where .= " AND t.id = :id";
            $collection->setParameter("id", $participanteId);
        } else {
            return null;
        }

        $collection->where($where)->setParameter("campanhaId", $campanhaId);

        $return = $collection->getQuery()->getScalarResult();
        return empty($return) ? null : $return[0];
    }

    private function calcularIdade(\DateTime $dataNascimento): int {
        $hoje = new \DateTime(); // Data atual
        $diferenca = $hoje->diff($dataNascimento); // Calcula a diferença entre as datas
        return $diferenca->y; // Retorna a idade em anos
    }


    private function createAplicacao($campanhaId, $participanteId, $entity = [])
    {
        if (empty($campanhaId)) {
            return false;
        }

        $oCampanha = $this->_em->getRepository('\App\Entity\Campanha')
            ->findOneBy(['id' => $campanhaId]);

        if (!$oCampanha) {
            return false;
        }

        // Campanha Pré-aprovada
        if ($oCampanha->getTipo() === 2) {
            $oParams = new \Stdclass;
            $oParams->campanhasId = $campanhaId;
            $oCampanhaVacinas = $this->_em->getRepository('\App\Entity\CampanhaVacina')
                ->fetchCollection($oParams, ['campanhaId' => $campanhaId]);

            if(empty($oCampanhaVacinas)) {
                return false;
            }

            $this->_em->getRepository('\App\Entity\Aplicacao')
                ->createAplicacoes($campanhaId, $participanteId, $oCampanhaVacinas);

            // TODO: Verificar se o cache esta funcionando
            $oVacina = $this->_em->getRepository('\App\Entity\Vacina')
                ->findOneBy(['id' => $oCampanhaVacinas[0]['vacinaId']]);

            // Verifica se deve cadastrar a aplicação extra por causa do parametro da vacina
            if($oVacina && $oVacina->getParDoseExtraIdade() && $entity['dtNascimento']) {
                $idade = $this->calcularIdade(new \DateTime($entity['dtNascimento']));
                if($oVacina->getParDoseExtraIdade() >= $idade) {
                    $this->_em->getRepository('\App\Entity\Aplicacao')
                        ->createAplicacoes($campanhaId, $participanteId, $oCampanhaVacinas);
                }
            }

            $this->update($participanteId, ['dtAceite' => date('Y-m-d H:i:s')]);
        }
    }

    public function cast($destination, $sourceObject)
    {
        if (is_string($destination)) {
            $destination = new $destination();
        }
        $sourceReflection = new \ReflectionObject($sourceObject);
        $destinationReflection = new \ReflectionObject($destination);
        $sourceProperties = $sourceReflection->getProperties();
        foreach ($sourceProperties as $sourceProperty) {
            $sourceProperty->setAccessible(true);
            $name = $sourceProperty->getName();
            $value = $sourceProperty->getValue($sourceObject);
            if ($destinationReflection->hasProperty($name)) {
                $propDest = $destinationReflection->getProperty($name);
                $propDest->setAccessible(true);
                $propDest->setValue($destination, $value);
            } else {
                $destination->$name = $value;
            }
        }
        return $destination;
    }

    private function splitFiles($fileName)
    {
        $path = realpath(dirname($fileName));
        $file = urlencode(utf8_encode(basename($fileName)));
        $time = time();
        $cmd = "split -l 500 --additional-suffix=.new_ {$path}/{$file} {$path}/{$time}_";
        echo exec($cmd);

        $fileNameOk = str_replace($file, "read_{$time}", $fileName);
        $this->renameFile($fileName, $fileNameOk);

        return glob("{$path}/{$time}*");
    }

    private function getHeader($file)
    {
        $cmd = "head -n 1 {$file}";
        return exec($cmd);
    }

    private function addHeader($file, $header)
    {
        $cmd = "sed -i '1s/^/{$header}\\n/' {$file}";
        return exec($cmd);
    }

    public function renameFile($file, $newname = null)
    {
        if (empty($newname)) {
            $newname = substr($file, 0, -1);
        }
        $cmd = "mv {$file} {$newname}";
        return exec($cmd);
    }

    public function bulkInsert($file)
    {
        $time1 = time();

        $files = $this->splitFiles($file);

        $data = [
            'originalFilename' => basename($file),
            'totalSplit' => count($files)
        ];

        $em = $this->getEntityManager();
        $oProcess = $em->getRepository('\App\Entity\ProcessUploadStatus')->create($data);
        $em->flush();

        $batchSize = 20; // Define o tamanho do lote para evitar consumo excessivo de memória
        $i = 0;
        foreach ($files as $file) {
            try {
                // Se o EntityManager estiver fechado, reabre ele
                if (!$em->isOpen()) {
                    $em = $em->create(
                        $this->_em->getConnection(),
                        $this->_em->getConfiguration()
                    );
                }

                $oItem = new \App\Entity\ProcessUploadStatusItems();
                $oItem->setFilename(basename(preg_replace('/_$/', '', $file)));
                $oItem->setProcessUploadStatusId($oProcess['id']);
                $oItem->setStatus(1);
                $oItem->setCreatedAt(new \DateTime());

                $em->persist($oItem);
                // Faz o flush a cada $batchSize inserções para melhor performance
                if (($i % $batchSize) === 0) {
                    $em->flush();
                    $em->clear(); // Limpa os objetos gerenciados da memória
                }
            }
            catch (\Exception $e) {
                echo "bulkInsert: " . $e->getMessage() . "\n";
            }
            $i++;
        }
        // Dá flush no que restou no buffer
        $em->flush();
        $em->clear();

        $header = [];
        foreach ($files as $k => $file) {
            if (!$k) {
                $header = $this->getHeader($file);
            }

            if (empty($header)) {
                die("FIM - ERRO\n");
            }

            if ($k) {
                $this->addHeader($file, $header);
            }

            $this->renameFile($file);
        }

        $time2 = time();
        echo "Total de arquivos: " . count($files) . "\n";
        echo "Tempo total processamento: " . ($time2 - $time1) . "s\n";
    }

    public function getFilesToInsert($path)
    {
        $files = glob("{$path}/*.new");
        $filesLock = $this->getFilesToInsertExclude($path);

        $newFiles = [];
        foreach ($files as $file) {
            $key = str_replace('.new', '', basename($file));
            if (!in_array($key, $filesLock)) {
                $newFiles[] = $file;
            }
        }

        return $newFiles;
    }

    public function getFilesToInsertExclude($path)
    {
        $filesEx = glob("{$path}/*.lock");
        $filesLock = [];
        foreach ($filesEx as $file) {
            $filesLock[] = preg_replace('/\..*/', '',  basename($file));
        }

        return $filesLock;
    }

    public function blockFile($file)
    {
        $file = fopen("{$file}.lock", 'a');
        fclose($file);
    }

    function isEmptyRow($row) {
        foreach($row as $cell){
            if (null !== $cell) return false;
        }
        return true;
    }

    public function processFile($file)
    {
        $em = $this->getEntityManager();

        if (!file_exists($file)) {
            throw new \Exception('Arquivo nao existe!');
        }

        // Desabilitando log
        $em->getConnection()->getConfiguration()->setSQLLogger(null);
        $rustart = getrusage();

        $count = 0;
        $limit = 3500;
        $time1 = time();
        $timeInterno = time();
        $headers = [];

        $path_parts = pathinfo($file);
        $fileNameLog = $path_parts['dirname'] . '/' . $path_parts['filename'] . '.log';
        $fileLog = fopen($fileNameLog, 'a');
        if (($handle = fopen($file, "r")) !== FALSE) {
            while (($row = fgetcsv($handle, 1000, ";")) !== FALSE) {
                $count++;
                if ($count === 1) {
                    $headers = $row;
                    fputcsv($fileLog, $row, ';');
                    continue;
                }

                $data = @array_combine($headers, $row);
                $data = array_map('trim', $data);
                try {
                    if($this->isEmptyRow($data)) {
                        throw new \Exception('Linha vazia');
                    }

                    if(empty($data['campanhaId'])) {
                        throw new \Exception('Sem codigo da campanha');
                    }

                    $cloneObj = clone $this;
                    $cloneObj->create($data);
                    fputcsv($fileLog, array_merge($data, ['SUCESSO']), ';');

                    $this->_em->flush();
                    $this->_em->clear(); // Detaches all objects from Doctrine!
                } catch (\Exception $e) {
                    fputcsv($fileLog, array_merge($data, [$e->getMessage()]), ';');
                    echo ('Data Participante: ' . serialize($data) . ' | Error: ' . $e->getMessage() . "\n");
                    if (!$this->_em->isOpen()) {
                        $this->_em = $this->_em->create(
                            $this->_em->getConnection(),
                            $this->_em->getConfiguration()
                        );
                    }
                }

                if ($count % 100 === 0) {
                    $timeInternoTemp = time();
                    $time = ($timeInternoTemp - $timeInterno);
                    $timeInterno = $timeInternoTemp;
                    echo "Total pocessado [{$count}] [{$time}s]\n";
                }
                // if ($count === $limit) {
                //     echo "Limite [{$limit}] atingido \n";
                //     break;
                // }
            }
            fclose($handle);
        }
        // Limite [50] atingido
        // Memory usage: 1.24 GiB / 1.94 GiB (63.583223158977%)
        // This process used 695 ms for its computations
        // It spent 140 ms in system calls

        // Limite [500] atingido
        // Memory usage: 1.24 GiB / 1.94 GiB (63.941600398589%)
        // This process used 27722 ms for its computations
        // It spent 1107 ms in system calls
        // Overall Time spent: 241s

        $time2 = time();

        $memUsage = $this->getServerMemoryUsage(false);
        echo sprintf(
            "Memory usage: %s / %s (%s%%)",
            $this->getNiceFileSize($memUsage["total"] - $memUsage["free"]),
            $this->getNiceFileSize($memUsage["total"]),
            $this->getServerMemoryUsage(true)
        );

        echo "\n";
        $ru = getrusage();
        echo "This process used " . $this->rutime($ru, $rustart, "utime") .
            " ms for its computations\n";
        echo "It spent " . $this->rutime($ru, $rustart, "stime") .
            " ms in system calls\n";
        echo "Overall Time spent: " . ($time2 - $time1) . "s\n";
    }

