    function sendEmail($campanhaId, $to, $tipo)
    {
        $oCampanha = $this->_em->getRepository('\App\Entity\Campanha')
            ->findOneBy(['id' => $campanhaId]);

        switch ($tipo) {
            case 'adesao':
                $subject = 'Vacinar - Aceite de Termo';
                $mensagemHTML = $this->getMensagemAdesao($oCampanha);
                break;
            case 'cancelar_adesao':
                $subject = 'Vacinar - Cancelamento de Adesão';
                $mensagemHTML = $this->getMensagemAdesaoCancelar($oCampanha);
                break;
            default:
                throw new \Exception('Bad Request!', 400);
        }

        $params = [
            'to' => $to,
            'subject' => $subject,
            'content' => $mensagemHTML
        ];

        $url = 'https://sgcsaude.com.br/sce/enviar_email.php';
        $client = new Client([
            'verify' => false,
            // Base URI is used with relative requests
            'base_uri' => $url,
            // You can set any number of default request options.
            // 'timeout'  => 2.0,
        ]);

        $response = $client->request('POST', $url, [
            'form_params' => $params
        ]);
        echo $response->getBody()->read(4);

        return 'enviado';
    }

    public function getTotalAdesaoParticipante($filters)
    {
        $collection = $this->createQueryBuilder("t")
            ->select("
                CASE WHEN t.dtAceite IS NULL THEN 'semAceite' ELSE 'comAceite' END AS totalAceite,
                COUNT(t.id) AS total
            ")
            ->leftJoin('\App\Entity\Empresa', 'emp', 'WITH', 'emp.id = t.empresaId')
            ;

        $where = '1=1 ';
        $where .= ' AND t.deletedAt IS NULL';
        $where .= ' AND t.campanhaId = :campanhaId';
        $collection->setParameter('campanhaId', $filters['campanhaId']);

        if (!empty($filters['empresaId'])) {
            $where .= ' AND t.empresaId = :empresaId ';
            $collection->setParameter('empresaId', $filters['empresaId']);
        }

        if (!empty($filters['uf'])) {
            $where .= ' AND emp.estado = :uf ';
            $collection->setParameter('uf', $filters['uf']);
        }

        $collection->where($where);

        $group = ' totalAceite ';
        $result = $collection->groupBy($group)->getQuery()->getResult();

        return $result;
    }
}
